css_snippet:
/* For main body text, a subtle adjustment can improve flow */
p {
  letter-spacing: 0.01em;
}

/* For large headings, to tighten visual spacing */
h1 {
  letter-spacing: -0.03em;
  font-weight: 700;
}

/* For small, all-caps text like labels or navigation, to enhance legibility */
.label {
  text-transform: uppercase;
  letter-spacing: 0.08em;
  font-size: 0.85rem;
  line-height: 1.2;
}
